@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (!string.IsNullOrEmpty(Title))
    {
        <h3 class="mb-4 text-base font-semibold text-foreground">@Title</h3>
    }
    @* <dl> (not <div>) so the <dt>/<dd> pairs emitted by DescriptionsItem have
       a valid definition-list ancestor; the grid classes stay on it. Each
       DescriptionsItem's wrapping <div> is a spec-valid dt/dd group container. *@
    @if (Bordered)
    {
        <div class="overflow-hidden rounded-lg border border-border/60">
            <dl class="@GridClasses">
                @ChildContent
            </dl>
        </div>
    }
    else
    {
        <dl class="@GridClasses">
            @ChildContent
        </dl>
    }
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Title { get; set; }
    [Parameter] public bool Bordered { get; set; }
    [Parameter] public int Column { get; set; } = 3;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(Class);

    private string GridClasses => Bordered
        ? $"grid {ColumnClasses} divide-x divide-y divide-border/60"
        : $"grid {ColumnClasses} gap-4";

    private string ColumnClasses => Column switch
    {
        1 => "grid-cols-1",
        2 => "grid-cols-2",
        4 => "grid-cols-4",
        _ => "grid-cols-3"
    };
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (!string.IsNullOrEmpty(Label))
    {
        <dt class="text-sm text-muted-foreground">@Label</dt>
    }
    <dd class="mt-1 text-sm text-foreground">
        @ChildContent
    </dd>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("p-3", Class);
}
